UPDATE party_member
SET status = 'LEAVE_RESERVED',
    leave_reserved_at = NOW()
WHERE party_id = #{partyId}
  AND user_id = #{userId}
  AND status = 'ACTIVE'

UPDATE party_member
SET status = 'ACTIVE',
    leave_reserved_at = NULL
WHERE party_id = #{partyId}
  AND user_id = #{userId}
  AND status = 'LEAVE_RESERVED'

UPDATE party_member
SET status = #{status}
WHERE id = #{memberId}

UPDATE party_member
SET role = #{role}
WHERE id = #{memberId}
